steps.query:
query GetOrganization($orgId: ID!) {
  org(where: { id: $orgId }) {
    id
    name
    website
    domain
    createdAt
    zone
    level
  }
}

query ListOrganizationsWithSummary($first: Int, $orderBy: OrgOrderByInput) {
  orgsConnection(first: $first, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        website
        level
        createdAt
        orgSummary {
          totalCampaigns
          liveCampaigns
          activeCampaigns
          impressions
          roas
          totalRevenue
          budget
        }
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
